            );
            ctx.fill();

            // 绘制蛇
            snake.forEach((segment, index) => {
                // 蛇头
                if (index === 0) {
                    ctx.fillStyle = '#4fd1c5';
                } else {
                    // 蛇身渐变
                    const green = Math.floor(180 - (index * 3));
                    ctx.fillStyle = `rgb(79, ${green}, 197)`;
                }

                ctx.beginPath();
                ctx.roundRect(
                    GAME_OFFSET_X + segment.x * GRID_SIZE + 1,
                    GAME_OFFSET_Y + segment.y * GRID_SIZE + 1,
                    GRID_SIZE - 2,
                    GRID_SIZE - 2,
                    4
                );
                ctx.fill();
            });

            // 绘制菜单或暂停界面
            if (gameState === GAME_STATE.MENU) {
                ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                ctx.fillStyle = '#fff';
                ctx.font = 'bold 36px "PingFang SC", "Microsoft YaHei", sans-serif';
                ctx.textAlign = 'center';
                ctx.fillText('贪食蛇', canvas.width / 2, canvas.height / 2 - 80);

                ctx.font = '18px "PingFang SC", "Microsoft YaHei", sans-serif';
                ctx.fillText('经典贪食蛇游戏', canvas.width / 2, canvas.height / 2 - 30);

                ctx.fillStyle = '#4fd1c5';
                ctx.fillText('按空格键开始游戏', canvas.width / 2, canvas.height / 2 + 30);

                ctx.fillStyle = '#aaa';
                ctx.font = '14px "PingFang SC", "Microsoft YaHei", sans-serif';
                ctx.fillText('使用方向键或WASD控制蛇的移动', canvas.width / 2, canvas.height / 2 + 80);
                ctx.fillText('吃到红色食物可以得分并变长', canvas.width / 2, canvas.height / 2 + 110);
            } else if (gameState === GAME_STATE.PAUSED) {
                ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                ctx.fillStyle = '#fff';
                ctx.font = 'bold 36px "PingFang SC", "Microsoft YaHei", sans-serif';
                ctx.textAlign = 'center';
                ctx.fillText('游戏暂停', canvas.width / 2, canvas.height / 2);

                ctx.font = '18px "PingFang SC", "Microsoft YaHei", sans-serif';
                ctx.fillText('按空格键继续', canvas.width / 2, canvas.height / 2 + 40);
            }
        }

        // 处理输入
        function handleInput(key, pressed) {
            if (!pressed) return;

            switch (gameState) {
                case GAME_STATE.MENU:
                    if (key === ' ') {
                        gameState = GAME_STATE.PLAYING;
                    }
                    break;

                case GAME_STATE.PLAYING:
                    switch (key) {
                        case 'ArrowUp':
                        case 'w':
                        case 'W':
                            if (direction !== 'down') nextDirection = 'up';
                            break;
                        case 'ArrowDown':
                        case 's':
                        case 'S':
                            if (direction !== 'up') nextDirection = 'down';
                            break;
                        case 'ArrowLeft':
                        case 'a':
                        case 'A':
                            if (direction !== 'right') nextDirection = 'left';
                            break;
                        case 'ArrowRight':
                        case 'd':
                        case 'D':
                            if (direction !== 'left') nextDirection = 'right';
                            break;
                        case ' ':
                            gameState = GAME_STATE.PAUSED;
                            break;
                    }
                    break;

                case GAME_STATE.PAUSED:
                    if (key === ' ') {
                        gameState = GAME_STATE.PLAYING;
                    }
                    break;

                case GAME_STATE.GAMEOVER:
                    if (key === ' ') {
                        resetGame();
                        gameState = GAME_STATE.PLAYING;
                    }
                    break;
            }
        }

        // 键盘事件监听
        document.addEventListener('keydown', (e) => {
            handleInput(e.key, true);
            // 阻止方向键滚动页面
            if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', ' '].includes(e.key)) {
                e.preventDefault();
            }
        });

        // 添加触摸控制（适用于移动设备）
        let touchStartX = 0;
        let touchStartY = 0;

        document.addEventListener('touchstart', (e) => {
            touchStartX = e.touches[0].clientX;
            touchStartY = e.touches[0].clientY;
        });

        document.addEventListener('touchend', (e) => {
            const touchEndX = e.changedTouches[0].clientX;
            const touchEndY = e.changedTouches[0].clientY;

            const dx = touchEndX - touchStartX;
            const dy = touchEndY - touchStartY;

            // 判断滑动方向
            if (Math.abs(dx) > Math.abs(dy)) {
                // 水平滑动
                if (dx > 30) {
                    handleInput('ArrowRight', true);
                } else if (dx < -30) {
                    handleInput('ArrowLeft', true);
                }
            } else {
                // 垂直滑动
                if (dy > 30) {
                    handleInput('ArrowDown', true);
                } else if (dy < -30) {
                    handleInput('ArrowUp', true);
                }
            }
        });

        // 初始化游戏
        initGame();
    </script>
